svg.script:
var languages = [
  { name: 'Lua', fill: '#ff8700', x: 10, y: 10 },
  { name: 'Python', fill: '#4b8bbc', x: 230, y: 10 },
  { name: 'HTML', fill: '#f0f0f0', x: 450, y: 10 },
  { name: 'CSS', fill: '#8a3b8a', x: 670, y: 10 }
];

languages.forEach(function(lang) {
  var rect = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
  rect.setAttribute('x', lang.x);
  rect.setAttribute('y', lang.y);
  rect.setAttribute('width', 200);
  rect.setAttribute('height', 200);
  rect.setAttribute('fill', lang.fill);
  document.getElementById('svgRoot').appendChild(rect);

  var text = document.createElementNS('http://www.w3.org/2000/svg', 'text');
  text.setAttribute('x', lang.x + 55);
  text.setAttribute('y', lang.y + 180);
  text.setAttribute('class', 'label');
  text.textContent = lang.name;
  document.getElementById('svgRoot').appendChild(text);
});
